query (
  $v1: pour_card_bool_exp,
  $v2: [pour_card_order_by!],
  $v3: Int,
  $v4: Int
) {
  pour_card(
    where: $v1,
    order_by: $v2,
    limit: $v3,
    offset: $v4
  ) {
    id
    pour_card_no
    project_name
    project_code
    specific_location
    created_by_user_id
    approval_status
    pour_card_approval_system {
      department_id
      team_member_id
      user_id
    }
    pour_details(order_by: { created_at: desc }, limit: 1) {
      pouring_date
      concrete_quantity
    }
  }
  pour_card_aggregate(where: $v1) {
    aggregate {
      count
    }
  }
}

